// LESSON: Reference Page 1 - Klass, objekt, konstruktor.
// You will learn: Build objects with fields, constructors, validation, and methods.
class Prog2Reference421 {
  // EXEMPEL 1: En klass beskriver vilka falt och metoder ett objekt far.
  static class Person {
    private final String name;
    private int age;
    Person(String name, int age) {
      this.name = name;
      this.age = age;
    }
    void birthday() { age++; }
    String label() { return name + " (" + age + ")"; }
  }
  // EXEMPEL 2: new skapar ett objekt som metoder kan anropas pa.
  static String createAndUseObject() {
    Person ada = new Person("Ada", 20);
    ada.birthday();
    return ada.label();
  }
  // EXEMPEL 3: En konstruktor kan validera innan objektet blir anvandbart.
  static class Rectangle {
    private final int width;
    private final int height;
    Rectangle(int width, int height) {
      if (width <= 0 || height <= 0) { throw new IllegalArgumentException("size"); }
      this.width = width;
      this.height = height;
    }
    int area() { return width * height; }
  }
}
